var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님…? 사장님…?! 다들 대체 어디 계세요오!","JPN":"先輩……？　社長……！？　みんなどこですかぁ！","ENG":"Mina...? Boss...?! Where is everyone?!","TWN":"前輩……？老闆……？！都跑哪去了？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히잉, 어떻게 해야 여기서 나갈 수 있는 거지?","JPN":"ひいん、どうやったらここから出られるの？","ENG":"Hngh... How am I supposed to get out of here?","TWN":"唉，我該怎麼離開這裡？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"넌… 누구야? 왜 여기서 소리지르고 있어?","JPN":"あなたは……誰？　なんでここで叫んでるの？","ENG":"Who... who are you? Why are you screaming?","TWN":"你……你是誰？為什麼在這裡大喊大叫？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어라? 당신은…?","JPN":"あれ？　あなたは……？","ENG":"Huh? You...?","TWN":"唉？你……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저랑 똑같이 생겼잖아요?! 세상에 어떻게 이런 일이!!","JPN":"私とそっくりじゃないですか！？　どういうこと！！","ENG":"You look just like me! Oh my gosh!!","TWN":"你長得跟我一模一樣？！這到底是怎麼回事！！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"내가… 너처럼 생겼다고? 그게 정말이야?","JPN":"私が……あなたにそっくりですって？　それって本当なの？","ENG":"I... look like you? Really?","TWN":"我……我長得像你？真的？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와, 뭐예요 그 이상한 반응은? 자기가 어떻게 생겼는지도 모른다고요?","JPN":"うわ、何ですかその反応。自分の顔もわからないのですか？","ENG":"Whoa, that's a weird reaction to have. Don't you know what you look like?","TWN":"哇，你反應怎麼這麼奇怪？難道連自己長什麼樣都不知道？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"몰랐어. 궁금해본 적 없으니까.","JPN":"知らなかった。気にしたこともないし。","ENG":"I didn't know. Because I've never really cared.","TWN":"我不知道，因為我從未想過。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 그러니까… 안녕하세요! 저는 노엘 라이트라고 해요!","JPN":"あ、ええと……こんにちは！　私はノエル・ライトといいます！","ENG":"Uh, well... Hi! I'm Noelle Wright!","TWN":"喔，那麼……嗨，我是洛艾兒·萊特！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아마, 당신의 이름도 노엘 라이트인 거죠?","JPN":"たぶん、あなたの名前もノエル・ライトなんですよね？","ENG":"I guess your name's also Noelle Wright?","TWN":"你應該也叫洛艾兒·萊特吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이름…? 노엘 라이트…?","JPN":"名前……？　ノエル・ライト……？","ENG":"Name...? Noelle Wright...?","TWN":"名字……？洛艾兒·萊特……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"맞아. 그런 이름을 가졌으면 좋겠다고 생각한 적이 있어.","JPN":"そうだ。そんな名前が欲しいと思ったことはあったよ。","ENG":"Yeah. I thought it'd be nice to have a name like that.","TWN":"沒錯，我曾希望自己也有這樣的名字。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"너, 나랑 마음이 잘 맞는구나!","JPN":"あなた、私と気が合うのね！","ENG":"You and I are gonna be good friends!","TWN":"你和我的想法太一致了！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음… 그러니까.","JPN":"えっと……その。","ENG":"Err... So...","TWN":"嗯……是這樣的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"전 동료분들과 함께 여기로 왔다가 길을 잃어버렸어요.","JPN":"私は仲間と一緒に来ましたけど、はぐれて道に迷ったのです。","ENG":"I came here with my colleagues, but I think I'm lost.","TWN":"我和幾個同伴來到這裡，結果迷路了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"혹시 여기서 어떻게 나가는지 알고 있나요? 동료들을 다시 만나야 하거든요.","JPN":"ここから出る方法を知っていますか？　仲間と会わなければいけないんですよ。","ENG":"Do you know how to get out of here? I really need to find them.","TWN":"你知道如何離開這裡嗎？我得趕快去找我的同伴。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"어… 꼭 나가야 해?","JPN":"え……どうしても出なければいけないの？","ENG":"Uh... Do you really have to go?","TWN":"呃……一定要離開嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"나랑 같이 있자. 나 여기 엄청 오랫동안 혼자만 있었거든.","JPN":"私と一緒にいようよ。私、長い間ここで一人だったんだ。","ENG":"Stay here with me. I've been here alone for a very long time.","TWN":"來陪我吧。我一個人在這裡已經很久了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으, 으… 저랑 똑같이 생긴 사람이 저런 표정으로 부탁해버리면…","JPN":"う、うぅ……私と同じ顔の人にあんな表情でお願いされると……","ENG":"Um... I don't know what to say when a person who looks exactly like me asks with that expression...","TWN":"唉，唉……和我長得一模一樣的人以那種表情拜託我……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"잠깐… 정도는 놀아줄 수도 있긴 하지만요. 바빠서 오래는 못 있어요?","JPN":"ちょっと……くらいなら遊べますけど、忙しいからそう長くは居られませんよ？","ENG":"Maybe... I can play with you for a little while. But I can't stay long, okay?","TWN":"我……我可以陪你玩一下下。但我很忙，不能待太久喔？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"헤헤, 고마워.","JPN":"へへ、ありがとう。","ENG":"He he, thanks.","TWN":"嘿嘿，謝謝。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그럼 이것 좀 볼래?","JPN":"じゃあ、これ見てみない？","ENG":"Then will you take a look at this?","TWN":"那看看這個吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오, 바닥에 나뭇가지로 그림 그리기네요!","JPN":"お、木の枝で地面に絵を描いたんですね！","ENG":"Oh, you're drawing on the ground with a stick!","TWN":"喔，用木頭在地板上畫畫！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 어릴 때 이런 거 자주 했어요!","JPN":"私も子供の頃よくやっていました！","ENG":"I used to do that a lot when I was a kid!","TWN":"我小時候經常這樣玩！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"정말? 그럼 이게 뭔지 알아 맞출 수 있어?","JPN":"本当？　じゃあ、これが何かわかる？","ENG":"Really? Then can you guess what I'm drawing?","TWN":"真的嗎，那你能猜到這是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음…!","JPN":"ううむ……！","ENG":"Um...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이건 손잡고 있는 커플, 이건 사과 나무, 그리고 이건 커다란 강아지네요!","JPN":"これは手を繋いでいるカップル、これはリンゴの木、そしてこれは大きいワンちゃんですね！","ENG":"This one's a couple holding hands, this is an apple tree, and the last one is a big puppy!","TWN":"這是一對牽手的情侶，這是一棵蘋果樹，這是一隻大狗！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"와아, 신기하다. 엄청 못 그렸다고 생각했는데, 이걸 맞히다니.","JPN":"わあ、不思議。凄く下手だと思ったのに、これがわかるなんて。","ENG":"Wow! That's amazing! I thought my drawings were horrible, but you got them all right.","TWN":"哇，太神奇了。我還以為自己畫得很糟糕，沒想到你都能猜到。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아니에요. 당신도 저만큼 잘 그리는데요?","JPN":"いいえ。あなたも私くらい上手ですよ？","ENG":"No, you're not. You draw just as well as I do.","TWN":"不，你畫得和我一樣好。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 이런 것들은 어디서 보고 그린 거죠? 여긴 나무나 강아지 같은 건 하나도 안 보이는데.","JPN":"でもこれはどこで見て描いたのですか？　ここには木やワンちゃんなんてまったく見当たらないのですが。","ENG":"But where have you seen these things to draw? I don't see any puppies or trees around here.","TWN":"但你是在哪裡看到這些的？ 我在這裡沒有看到任何樹木或小狗。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"꿈에서 본 거야. 난 꿈을 꿀 때마다 많은 걸 보거든.","JPN":"夢で見たの。私は夢を見るたびに色んなものをたくさん見るからね。","ENG":"I saw them in my dreams. I see a lot of things when I dream.","TWN":"我在夢裡看到的，我在夢裡會看到很多東西。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이건 그 중에서도 내 기억에 남는 가장 갖고 싶은 것들을 그린 거고.","JPN":"これはその中でも私の記憶に残っている一番欲しいものを描いたの。","ENG":"I drew the things that are most memorable and desirable to me.","TWN":"而這些是我最想保留的記憶。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"아, 그리고 얜 그냥 큰 강아지가 아니라, 골든 리트리버라는 견종이야.","JPN":"あ、そしてこの子はただ大きいワンちゃんではなく、ゴールデン・レトリバーという犬種だよ。","ENG":"Oh, and that's not just a big puppy, it's a golden retriever.","TWN":"喔，牠不是普通的大狗，是一隻黃金獵犬。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그거 우연이네요. 저희 집에서 키우는 개도…","JPN":"それは偶然ですね。私の家で飼っている犬も……","ENG":"What a coincidence. The dog I have at home is also...","TWN":"真巧，我們家養的狗也是……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"이름은 치즈.","JPN":"名前はチーズ。","ENG":"His name is Cheese.","TWN":"名字叫起司。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"색깔이랑 어울리지? 아빠엄마의 농장을 지켜주는 충성스러운 친구야.","JPN":"毛の色にぴったりでしょ？　お父さんとお母さんの農場を守ってくれる忠誠心が強い友達だよ。","ENG":"Doesn't his name go well with his fur? He's a loyal dog that protects my parents' farm.","TWN":"很適合牠吧？牠會幫爸爸媽媽保護農場，是對我很忠誠的朋友。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신한테 정말 그런 이름의 개가 있다고요?","JPN":"あなたに本当にそんな名前の犬がいるんですか？","ENG":"Do you really have a dog with that name?","TWN":"你真養了一隻叫起司的狗？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"노, 놀리는 거 아니지? 말했잖아. 이건 내가 정말 있는 게 아니라, 갖고 싶은 거라구.","JPN":"か、からかっているの？　言ったでしょう。これは本当にあるものではなくて、私が欲しいものだって。","ENG":"Y-you're not teasing me, right? I told you. These are not things that I really have, but things I want.","TWN":"你、你沒騙我吧？我說過，這是我想要的，而不是已經擁有的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"치즈도… 엄마 아빠도… 이런 넓은 과일숲도…","JPN":"チーズも……お母さんも、お父さんも……こんな広い果樹園も……","ENG":"Cheese... Mom and Dad... and even the vast orchard...","TWN":"起司……爸爸媽媽……還有這個大果林……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"나한텐… 아무것도 없단 말이야.","JPN":"私には……何もないんだ。","ENG":"You see... I have none of those.","TWN":"我……什麼都沒有。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신… 정체가 뭐죠?","JPN":"あなた……何者ですか？","ENG":"Who... are you?","TWN":"你……你是誰？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};